import{_ as e,a as t,b as n,c as i}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as r,c as l,a2 as u}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup dan Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/redundant-backup-and-read-source.md","filePath":"id-ID/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"id-ID/Other/redundant-backup-and-read-source.md"};function c(s,a,h,k,b,m){return r(),l("div",null,[...a[0]||(a[0]=[u('<h1 id="redundant-backup-dan-read-source-switching" tabindex="-1">Redundant Backup dan Read Source Switching <a class="header-anchor" href="#redundant-backup-dan-read-source-switching" aria-label="Permalink to &quot;Redundant Backup dan Read Source Switching&quot;">​</a></h1><p>Redundant backup menyimpan salinan tambahan dari file yang sudah diupload.</p><p>File utama dan file backup sama-sama bisa dipakai sebagai read source. Bagi pengunjung, biasanya tidak ada perbedaan. Satu-satunya perbedaan adalah storage channel mana yang menyajikan file tersebut.</p><h2 id="yang-bisa-dilakukan-redundant-backup" tabindex="-1">Yang Bisa Dilakukan Redundant Backup <a class="header-anchor" href="#yang-bisa-dilakukan-redundant-backup" aria-label="Permalink to &quot;Yang Bisa Dilakukan Redundant Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fitur</th><th>Keterangan</th></tr></thead><tbody><tr><td>Menyimpan salinan tambahan</td><td>Membackup file ke upload channel lain untuk mengurangi risiko jika satu channel bermasalah.</td></tr><tr><td>Mengganti read source</td><td>Setelah backup berhasil, pembacaan file bisa dipindah antara primary channel dan backup channel.</td></tr><tr><td>Backup satu file</td><td>Membackup satu file dari halaman detail file.</td></tr><tr><td>Batch backup</td><td>Memilih beberapa file di halaman admin lalu membackupnya bersama-sama.</td></tr><tr><td>Global redundant backup</td><td>Membackup file berdasarkan folder dari Other Settings.</td></tr></tbody></table><h2 id="entry-redundant-backup" tabindex="-1">Entry Redundant Backup <a class="header-anchor" href="#entry-redundant-backup" aria-label="Permalink to &quot;Entry Redundant Backup&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>Entry ini paling cocok untuk menambahkan backup ke satu folder atau ke semua file secara massal.</p><p>Backup channel bisa dipilih manual, atau Anda bisa memilih automatic switching agar ImgBed mencari backup channel yang sesuai.</p><h2 id="backup-dari-file-details" tabindex="-1">Backup dari File Details <a class="header-anchor" href="#backup-dari-file-details" aria-label="Permalink to &quot;Backup dari File Details&quot;">​</a></h2><p>Buka halaman detail file di panel admin, lalu klik backup.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>Cara ini paling cocok untuk membackup satu file penting sesuai kebutuhan.</p><p>Setelah backup berhasil, halaman detail file menampilkan read source yang tersedia.</p><h2 id="batch-backup-dari-pilihan-file" tabindex="-1">Batch Backup dari Pilihan File <a class="header-anchor" href="#batch-backup-dari-pilihan-file" aria-label="Permalink to &quot;Batch Backup dari Pilihan File&quot;">​</a></h2><p>Di panel admin, pilih beberapa file dan jalankan batch backup.</p><p><img src="'+n+'" alt="Batch backup" loading="lazy"></p><p>Cara ini cocok untuk memproses sekumpulan file.</p><p>Backup berdasarkan pilihan, backup dari file details, dan redundant backup di Other Settings semuanya memakai sistem backup yang sama. Bedanya hanya titik masuknya.</p><h2 id="mengganti-read-source-setelah-backup" tabindex="-1">Mengganti Read Source Setelah Backup <a class="header-anchor" href="#mengganti-read-source-setelah-backup" aria-label="Permalink to &quot;Mengganti Read Source Setelah Backup&quot;">​</a></h2><p>Setelah backup selesai, halaman detail file memungkinkan Anda mengganti read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Keterangan</th></tr></thead><tbody><tr><td>Primary channel</td><td>Membaca dari upload channel asli.</td></tr><tr><td>Backup channel</td><td>Membaca dari backup channel.</td></tr></tbody></table><p><img src="'+i+'" alt="Switch read source after backup" loading="lazy"></p><p>Pengunjung tidak perlu tahu apakah file disajikan dari primary channel atau backup channel.</p><p>Read source yang Anda pilih akan menjadi sumber utama untuk akses file berikutnya.</p><h2 id="kapan-backup-dilewati" tabindex="-1">Kapan Backup Dilewati <a class="header-anchor" href="#kapan-backup-dilewati" aria-label="Permalink to &quot;Kapan Backup Dilewati&quot;">​</a></h2><p>Kasus berikut akan dilewati saat backup. Ini bukan error.</p><table tabindex="0"><thead><tr><th>Kasus</th><th>Kenapa Dilewati</th></tr></thead><tbody><tr><td>Sudah memiliki backup</td><td>File yang sudah punya backup tidak dibackup ulang.</td></tr><tr><td>Primary dan backup channel sama</td><td>Backup harus disimpan di channel lain agar bermakna.</td></tr><tr><td>Tidak ada backup channel yang bisa dipakai</td><td>Tidak ada channel alternatif yang sesuai.</td></tr></tbody></table><p>Singkatnya: backup harus masuk ke channel lain, dan file yang sudah dibackup tidak memakai ruang tambahan lagi.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Nama</th><th>Arti</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel yang dipakai saat file pertama kali diupload.</td></tr><tr><td>Backup channel</td><td>Channel yang menyimpan salinan redundant.</td></tr><tr><td>Primary read source</td><td>File saat ini dibaca dari primary channel.</td></tr><tr><td>Backup read source</td><td>File saat ini dibaca dari backup channel.</td></tr></tbody></table><p>Primary dan backup read source memiliki perilaku yang sama bagi pengguna.</p><p>Selama file backup masih tersedia, gambar, video, dan link download tetap berjalan setelah read source dipindah ke backup.</p><h2 id="apa-yang-terjadi-saat-file-dihapus" tabindex="-1">Apa yang Terjadi Saat File Dihapus <a class="header-anchor" href="#apa-yang-terjadi-saat-file-dihapus" aria-label="Permalink to &quot;Apa yang Terjadi Saat File Dihapus&quot;">​</a></h2><p>Saat file dihapus, ImgBed akan menghapus file utama dan file backup.</p>',37)])])}const f=d(p,[["render",c]]);export{y as __pageData,f as default};
